DO $$
DECLARE
  v_visible_count INTEGER;
  v_backup_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_visible_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '19-21m'
    AND ct.slug IN ('cat_doll_soft_toy_care', 'cat_feelings_faces_books', 'cat_first_word_picture_books', 'cat_potty_books', 'cat_pouring_jug_cups', 'cat_safety_gates', 'cat_shape_sorters_puzzles', 'cat_soft_graspable_balls')
    AND s.status = 'visible'
    AND s.is_visible = true;

  IF v_visible_count <> 55 THEN
    RAISE EXCEPTION 'Expected 55 visible Stage 3 picks for 19-21m, got %', v_visible_count;
  END IF;

  SELECT COUNT(*) INTO v_backup_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '19-21m'
    AND ct.slug IN ('cat_doll_soft_toy_care', 'cat_feelings_faces_books', 'cat_first_word_picture_books', 'cat_potty_books', 'cat_pouring_jug_cups', 'cat_safety_gates', 'cat_shape_sorters_puzzles', 'cat_soft_graspable_balls')
    AND s.status = 'backup'
    AND s.is_visible = false;

  IF v_backup_count <> 11 THEN
    RAISE EXCEPTION 'Expected 11 backup Stage 3 picks for 19-21m, got %', v_backup_count;
  END IF;
END $$;

COMMIT;
